  const dataLine = text.split(/\r?\n/).find((l) => l.startsWith('data: '));
  if (!dataLine) throw new Error('Invalid MCP create response: ' + text.slice(0, 500));
  const payload = JSON.parse(dataLine.slice(6));
  if (payload.error) throw new Error(payload.error.message || JSON.stringify(payload.error));
  const t = payload.result?.content?.[0]?.text;
  return t ? JSON.parse(t) : (payload.result?.structuredContent || {});
}
const http = $input.first().json;
const created = parseMcpSse(http.body ?? http.data ?? '');
const built = $('Build SDK Payload').first().json;
const webhookUrl = `http://localhost:5678/webhook-test/${built.webhookPath}`;
return [{
  json: {
    success: true,
    workflowId: created.workflowId,
    name: created.name,
    url: created.url,
    nodeCount: created.nodeCount,
    webhookPath: built.webhookPath,
    response: `Created webhook workflow "${created.name}". Open ${created.url} to activate it, then POST to ${webhookUrl} (or http://localhost:5678/webhook/${built.webhookPath} once activated).`,
  },
}];
